INSERT INTO score (
    team_id, teacher_id, ai_report_id, doc_score, attendance_score,
    system_score, defense_score, total_score, teacher_comment, status
) VALUES (
    #{teamId}, #{teacherId}, #{aiReportId}, #{docScore}, #{attendanceScore},
    #{systemScore}, #{defenseScore}, #{totalScore}, #{teacherComment}, #{status}
)

INSERT INTO student_score (
    score_id, team_id, student_id, contribution_factor,
    personal_score, grade, teacher_comment
) VALUES (
    #{scoreId}, #{teamId}, #{studentId}, #{contributionFactor},
    #{personalScore}, #{grade}, #{teacherComment}
)

mapper.select:
SELECT s.score_id, s.team_id, ti.team_name, s.teacher_id, t.teacher_name, s.doc_score, s.attendance_score, s.system_score, s.defense_score, s.total_score, s.teacher_comment, s.status, s.create_time, s.update_time FROM score s LEFT JOIN team_info ti ON s.team_id = ti.team_id LEFT JOIN teacher t ON s.teacher_id = t.teacher_id WHERE 1 = 1
AND (ti.team_name LIKE CONCAT('%', #{keyword}, '%') OR t.teacher_name LIKE CONCAT('%', #{keyword}, '%'))
AND s.team_id = #{teamId}
AND s.teacher_id = #{teacherId}
AND s.status = #{status}
ORDER BY s.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM score s
LEFT JOIN team_info ti ON s.team_id = ti.team_id
LEFT JOIN teacher t ON s.teacher_id = t.teacher_id
WHERE 1 = 1

    AND (ti.team_name LIKE CONCAT('%', #{keyword}, '%')
         OR t.teacher_name LIKE CONCAT('%', #{keyword}, '%'))


    AND s.team_id = #{teamId}


    AND s.teacher_id = #{teacherId}


    AND s.status = #{status}

SELECT ti.team_id, ti.team_name, pt.topic_id, pt.topic_name, (SELECT COUNT(*) FROM stage_task) AS total_stage_count, COUNT(DISTINCT se.stage_id) AS evaluated_stage_count, COALESCE(AVG(se.total_score), 0) AS average_stage_score FROM team_info ti LEFT JOIN topic_selection ts ON ti.team_id = ts.team_id AND ts.audit_status = 1 LEFT JOIN project_topic pt ON ts.topic_id = pt.topic_id LEFT JOIN stage_evaluation se ON ti.team_id = se.team_id WHERE ti.is_deleted = 0
AND ti.team_id = #{teamId}
GROUP BY ti.team_id, ti.team_name, pt.topic_id, pt.topic_name ORDER BY ti.team_id ASC

SELECT s.score_id, s.team_id, ti.team_name, s.teacher_id, t.teacher_name, s.doc_score, s.attendance_score, s.system_score, s.defense_score, s.total_score, s.teacher_comment, s.status, s.create_time, s.update_time FROM score s LEFT JOIN team_info ti ON s.team_id = ti.team_id LEFT JOIN teacher t ON s.teacher_id = t.teacher_id WHERE 1 = 1
AND s.teacher_id = #{teacherId}
ORDER BY s.total_score DESC
